UPDATE jobs SET user_contributed_json = '{"way":"도로운송사무원이 되려면 물류·운송·경영학과를 졸업한 후 운수회사나 물류업체에 사무직으로 지원하는 것이 일반적이다.[1] 일부 기업은 고졸도 채용하나 대형 운수기업은 전문학사 이상을 선호한다. 취업 후에는 배차·수송계획·운행관리 등 실무를 익히고,[2] 물류관리사 자격증을 취득하면 승진과 전문직 전환에 유리하다.[3] 경력 5년 이상이면 물류팀장이나 운송관리자로 성장할 수 있다.[4]","overviewSalary":{"sal":"연봉 중위값은 약 3,000만~3,500만 원 수준이다.[1] 대형 화물운수업체나 택배사 정규직의 경우 복리후생이 충실하며, 경력 5년 이상 시 4,000만 원 이상도 가능하다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"향후 5~10년간 현상 유지 또는 소폭 감소할 것으로 예상된다.[1] 물류 자동화·AI 배차 플랫폼 도입으로 단순 배차 업무는 줄지만, e커머스 성장에 따른 고급 물류 관리 수요는 꾸준히 유지된다.[2]","source":"한국고용정보원(2024)"},"trivia":"한국의 화물차 등록 대수는 350만 대를 넘어 OECD 인구 대비 최고 수준으로, 도로운송사무원의 역할이 핵심적이다.[1] 대형 물류센터 한 곳에서 하루 최대 100만 건 이상의 배차 데이터가 처리된다.[2] TMS(수송관리시스템) 도입으로 배차 오류율이 과거 대비 60% 이상 감소했다는 업계 보고가 있다.[3]","detailWlb":{"wlb":"보통","social":"보통","wlbDetail":"기본적으로 주 5일 사무직 근무이나, 명절·연말 물동량 집중 시기에는 야근이 불가피하다. 긴급 배차 오류나 사고 발생 시 즉각 대응이 필요해 정시 퇴근이 어려울 수 있다.","socialDetail":"현장 운전기사와 회사 간 소통 창구 역할로 조직 내 인지도가 있다. 다만 현장직 대비 급여 격차로 상대적 박탈감을 느끼는 경우도 있다."},"detailReady":{"curriculum":["물류시스템개론·교통물류학 전공 이수","기업 물류 ERP 소프트웨어 활용 실습","물류관리사 시험 준비","화물자동차 운수사업법 등 관련 법규 숙지"],"recruit":["대형 운수·화물회사 사무직 공개채용 응시","물류기업 계약직·인턴십 지원 후 정규직 전환","공공기관(코레일 로지스틱스 등) 물류 사무직 지원"],"training":["물류관리사 자격증 취득(한국산업인력공단)","TMS·WMS 등 물류 소프트웨어 교육 수강","화물운송종사자 제도 이해 및 관련 업무 역량 향상"]},"sidebarJobs":["무역사무원","물류사무원","생산관리사무원","수상운송사무원","자재구매사무원","철도·지하철운송사무원","품질관리사무원","항공운송사무원"],"sidebarMajors":["물류학과","유통물류과","경영학과","경영정보학과","철도경영과","물류시스템공학과"],"sidebarCerts":["물류관리사","유통관리사","화물운송종사자격증","운전면허(1종보통)","교통안전관리자"],"heroTags":["도로운송사무원","배차원","운수사무원","물류사무","화물배차관리","운송관리"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":3,"text":"Q-Net 물류관리사","url":"https://www.q-net.or.kr/crf005.do?id=crf00505&gSite=Q&gId="},{"id":4,"text":"한국물류진흥원","url":"https://www.klpf.or.kr/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원 직업전망","url":"https://www.keis.or.kr/main/publish/qustionnaire/listview.do"},{"id":8,"text":"물류신문","url":"https://www.klnews.co.kr/"}],"trivia":[{"id":9,"text":"국토교통부 자동차등록현황","url":"https://www.molit.go.kr/"},{"id":10,"text":"한국물류진흥원","url":"https://www.klpf.or.kr/"},{"id":11,"text":"한국통합물류협회","url":"https://www.kila.or.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283421371269';

UPDATE jobs SET user_contributed_json = '{"way":"이용사가 되려면 먼저 이용사 자격증을 취득해야 한다.[1] 이용사 자격증은 국가기술자격으로, 이용 관련 전문학교·직업훈련원에서 1,200시간 이상의 교육·실습을 이수한 후 한국산업인력공단이 시행하는 필기·실기 시험에 합격하면 된다.[2] 자격증 취득 후 이발소, 바버샵, 호텔 이용실 등에 취업하거나, 경력을 쌓아 직접 개업할 수 있다.[3] 최근에는 클래식 바버샵 문화 확산으로 남성 전문 헤어숍 창업 수요가 늘고 있다.[4]","overviewSalary":{"sal":"이용사의 연봉은 취업 형태에 따라 크게 다르다.[1] 고용직의 경우 연 2,400만~3,000만 원 수준이며, 개업 시 매출에 따라 수익이 달라진다. 도심 유명 바버샵 원장의 경우 연 6,000만 원 이상의 수입도 가능하다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"이용사의 고용은 향후 5~10년간 다소 감소할 전망이다.[1] 미용사(일반)와 시장이 겹치고 소규모 이발소 폐업이 늘고 있으나, 클래식 바버 문화 확산과 남성 그루밍 시장 성장으로 프리미엄 바버샵 분야는 성장 중이다.[2]","source":"커리어넷, 한국고용정보원(2024)"},"trivia":"이용사와 미용사(일반)는 법적으로 구분되며, 이용사 면허가 있어야 면도(셰이빙) 서비스를 제공할 수 있다.[1] 한국의 공중위생관리법에 따르면 이용업소 개설 시 반드시 이용사 면허 소지자가 있어야 한다.[2] 최근 5년간 바버샵으로 등록된 이용업소 수가 30% 이상 증가했다는 통계가 있다.[3] 영국 왕실 이발사는 버킹엄궁에서 대대로 이발을 담당하는 전통이 있을 정도로 이용 기술은 숙련 장인직이다.[4]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"주말과 공휴일에도 영업하는 경우가 많아 주 5일 근무가 어렵다. 하루 종일 서서 일하는 직업 특성상 체력 소모가 크고, 성수기(명절 전후, 개학 시즌)에는 고강도 노동이 이어진다.","socialDetail":"단골 고객과의 유대감이 강하고 지역사회에서 친숙한 생활 서비스직으로 인식된다. 숙련된 이용사는 단순 기술자가 아닌 그루밍 전문가로서 전문성을 인정받는다."},"detailReady":{"curriculum":["이용 관련 직업훈련원 또는 전문학교 등록(1,200시간 이상 이수)","헤어커팅·면도·두피관리 기초 실기 훈련","이용사 필기시험 준비(공중보건학, 소독법, 피부학 등)","바버샵 트렌드 및 클래식 기법 학습"],"recruit":["이발소·바버샵 보조 스태프로 입사 후 경력 축적","호텔 이용실·병원 이용실 채용 공고 응시","이용사 자격 취득 후 창업(소자본 가능)"],"training":["이용사 국가기술자격증 취득(한국산업인력공단)","두피·모발관리 전문가 과정 수강","바버 아카데미 심화 교육 이수","피부관리 연계 자격(미용사 피부) 추가 취득"]},"sidebarJobs":["네일아티스트","메이크업아티스트 및 뷰티매니저","미용사","반려동물미용사","분장사","스타일리스트","피부 및 체형관리사"],"sidebarMajors":["미용과","뷰티미용학과","뷰티아트과","피부미용과","경영학과","관광경영과"],"sidebarCerts":["이용사","미용사(일반)","두피모발관리사","퍼머넌트웨이브사","피부관리사"],"heroTags":["이용사","이발사","바버","남성미용","헤어스타일리스트","이발소","바버샵"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"Q-Net 이용사 자격정보","url":"https://www.q-net.or.kr/crf005.do?id=crf00505&gSite=Q&gId="},{"id":2,"text":"한국산업인력공단","url":"https://www.hrdkorea.or.kr/"},{"id":3,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":4,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"커리어넷 직업전망","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":8,"text":"한국고용정보원","url":"https://www.keis.or.kr/"}],"trivia":[{"id":9,"text":"공중위생관리법(법제처)","url":"https://www.law.go.kr/"},{"id":10,"text":"공중위생관리법(법제처)","url":"https://www.law.go.kr/"},{"id":11,"text":"한국이용사회 중앙회","url":"https://www.hairkorea.or.kr/"},{"id":12,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"detailWlb.wlbDetail":[{"id":13,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":14,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283355706504';

UPDATE jobs SET user_contributed_json = '{"way":"마케팅·광고·홍보관리자는 대부분 마케팅·광고·경영학 관련 전공 졸업 후 기업의 마케팅팀 실무자로 입사하면서 경력을 시작한다.[1] 5~10년간 팀원·주임·팀장을 거쳐 마케팅 부서를 총괄하는 관리자로 승진하는 것이 일반적인 경로이다.[2] 디지털 마케팅, 브랜드 전략, 광고 기획 분야의 전문성을 쌓으면 CMO(최고마케팅책임자)나 전략기획 임원으로 성장할 수 있다.[3] MBA 취득이나 해외 근무 경험이 고위직 진출에 도움이 된다.[4]","overviewSalary":{"sal":"마케팅·광고·홍보관리자의 평균 연봉은 약 6,000만~8,000만 원 수준이다.[1] 대기업 마케팅 임원의 경우 성과급을 포함해 1억 원 이상도 가능하며, 중소기업 관리자는 4,500만~6,000만 원 수준이다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"마케팅·광고·홍보관리자의 수요는 향후 5~10년간 완만한 성장세가 예상된다.[1] 디지털 전환 가속으로 데이터 기반 마케팅 전문 관리자에 대한 수요가 증가하고 있으며, 퍼포먼스 마케팅·콘텐츠 마케팅 분야 관리자 수요가 특히 늘고 있다.[2]","source":"한국고용정보원, 커리어넷(2024)"},"trivia":"국내 기업의 마케팅 예산은 매출의 평균 5~10%를 차지하며, 이를 총괄하는 마케팅관리자의 의사결정이 기업 브랜드 가치에 직접 영향을 준다.[1] 전 세계 디지털 광고 시장은 2024년 기준 약 700조 원 규모로, 한국도 디지털 광고비 비중이 전체 광고비의 60%를 넘었다.[2] 유명 광고 캠페인 하나로 기업 매출이 30% 이상 증가한 사례가 있을 정도로 마케팅 관리자의 전략적 판단이 중요하다.[3]","detailWlb":{"wlb":"보통","social":"높음","wlbDetail":"캠페인 런칭이나 신제품 출시 전후에는 집중 근무가 이어지며, 성과 압박이 상당하다. 평소에는 유연 근무가 가능한 편이나 업계 특성상 주말 이벤트나 프로모션 대응이 필요한 경우가 많다.","socialDetail":"기업 내에서 마케팅·홍보 관리자는 브랜드의 얼굴로 인식되어 사내 영향력이 높다. 외부 에이전시, 미디어, 인플루언서 등 다양한 네트워크를 보유하여 사회적 인지도도 높은 편이다."},"detailReady":{"curriculum":["경영학·마케팅·광고학 관련 학과 전공 이수","디지털 마케팅(SEO, SEM, SNS) 실무 능력 배양","광고 캠페인 기획 및 데이터 분석 실습","해외 마케팅·브랜딩 사례 연구"],"recruit":["대기업 마케팅팀 신입·경력 공개채용 응시","광고대행사·PR회사 입사 후 클라이언트 기업 이직","스타트업 마케터로 시작하여 팀 구축 후 관리자로 성장"],"training":["디지털마케팅 전문가(DMK) 자격 취득","구글 애널리틱스·메타 인증 광고 전문가 자격 취득","MBA(경영전문대학원) 진학으로 전략 역량 강화","마케팅 협회 세미나·컨퍼런스 정기 참여"]},"sidebarJobs":["경영지원관리자","광고·홍보·마케팅사무원","광고·홍보·마케팅전문가","금융관리자","보험관리자","정부행정관리자"],"sidebarMajors":["경영학과","광고·홍보학과","경제학과","광고기획과","마케팅경영과","통계학과"],"sidebarCerts":["광고기획사1급","디지털마케팅전문가","경영지도사","구글애널리틱스인증","SNS광고마케터"],"heroTags":["마케팅관리자","광고관리자","홍보관리자","CMO","브랜드매니저","마케팅임원"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":3,"text":"한국광고협회","url":"https://www.kaa.or.kr/"},{"id":4,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":8,"text":"커리어넷 직업전망","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"trivia":[{"id":9,"text":"한국광고총연합회","url":"https://www.kaa.or.kr/"},{"id":10,"text":"과학기술정보통신부 디지털광고 보고서","url":"https://www.msit.go.kr/"},{"id":11,"text":"한국마케팅협회","url":"https://www.kma.re.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283407073895';

UPDATE jobs SET user_contributed_json = '{"way":"교재·교구 및 이러닝교육전문가가 되려면 교육학·교육공학·경영정보학 관련 학과를 졸업한 후 교육 콘텐츠 회사, 이러닝 기업, 출판사 등에 입사하는 것이 일반적이다.[1] 교수설계(Instructional Design) 역량과 콘텐츠 기획력이 핵심이며, 교육업체 기획팀이나 콘텐츠 개발팀에서 경력을 쌓는다.[2] 이러닝운영관리사 등 관련 자격을 취득하면 전문성을 인정받을 수 있으며,[3] 에듀테크 스타트업에서 경험을 쌓아 교육 플랫폼 기획자로 성장하는 사례도 늘고 있다.[4]","overviewSalary":{"sal":"교재·교구 및 이러닝교육전문가의 연봉은 약 2,800만~4,500만 원 수준이다.[1] 대형 교육 기업이나 에듀테크 플랫폼 회사의 경우 더 높은 처우를 받기도 하며, 경력 7년 이상의 수석 교수설계자는 5,000만 원 이상도 가능하다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"이러닝교육 시장 확대와 에듀테크 성장으로 관련 전문가 수요는 증가할 전망이다.[1] 비대면 교육 확산, 기업 내 교육 디지털화, AI 기반 학습 플랫폼 개발이 맞물려 교수설계·콘텐츠 개발 역량을 갖춘 전문가에 대한 수요가 높아지고 있다.[2]","source":"한국이러닝산업협회, 한국고용정보원(2024)"},"trivia":"한국은 세계 최고 수준의 이러닝 인프라를 보유한 나라로, OECD 회원국 중 이러닝 활용률 상위권을 유지하고 있다.[1] 국내 이러닝 시장 규모는 2023년 기준 약 5조 원을 넘어섰으며 매년 성장하고 있다.[2] 효과적인 교재 설계 하나가 학습자 성취율을 최대 40% 이상 향상시킬 수 있다는 연구 결과도 있다.[3]","detailWlb":{"wlb":"보통이상","social":"보통","wlbDetail":"콘텐츠 개발 마감 전후에는 집중 근무가 필요하나, 평소에는 자율 근무제를 운영하는 회사가 많다. 재택근무 비율이 높은 직군이기도 하다.","socialDetail":"교육 분야 전문가로서 사회적 인식이 나쁘지 않다. 학습자의 학업 성취를 직접적으로 돕는다는 직업적 보람이 크며, 교육업계 네트워크를 통해 다양한 협업 기회를 갖는다."},"detailReady":{"curriculum":["교육학·교육공학 전공 이수","교수설계 이론(ADDIE, SAM 모델) 학습","이러닝 콘텐츠 저작 도구(Articulate, Adobe Captivate) 실습","교육 데이터 분석 및 학습관리시스템(LMS) 운영 이해"],"recruit":["교육 출판사·이러닝 기업 콘텐츠 기획팀 공채 응시","에듀테크 스타트업 교육 기획자 채용 응시","대기업 HRD팀 교육 콘텐츠 개발직 지원"],"training":["이러닝운영관리사 자격증 취득","멀티미디어콘텐츠제작전문가 자격 취득","교수설계 전문과정 수료(한국직업능력연구원 등)","AI 기반 학습 플랫폼 기획 역량 강화 교육"]},"sidebarJobs":["이러닝교수설계운영관리자","장학관","문리학원강사","컴퓨터강사","기술·기능계강사","학습지방문교사","예능강사","외국어강사","인사·교육·훈련사무원"],"sidebarMajors":["교육학과","교육공학과","경영정보학과","아동·청소년복지학과","경영학과","통계학과"],"sidebarCerts":["이러닝운영관리사","멀티미디어콘텐츠제작전문가","교원자격증","컴퓨터그래픽스운용기능사","정보처리기사"],"heroTags":["이러닝전문가","교육콘텐츠개발","교재개발","교수설계자","에듀테크","학습콘텐츠"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":3,"text":"Q-Net 이러닝운영관리사","url":"https://www.q-net.or.kr/crf005.do?id=crf00505&gSite=Q&gId="},{"id":4,"text":"한국이러닝산업협회","url":"https://www.koela.or.kr/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국이러닝산업협회","url":"https://www.koela.or.kr/"},{"id":8,"text":"한국고용정보원","url":"https://www.keis.or.kr/"}],"trivia":[{"id":9,"text":"한국이러닝산업협회","url":"https://www.koela.or.kr/"},{"id":10,"text":"정보통신산업진흥원(NIPA)","url":"https://www.nipa.kr/"},{"id":11,"text":"한국직업능력연구원","url":"https://www.krivet.re.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283459307220';

UPDATE jobs SET user_contributed_json = '{"way":"신용분석가가 되려면 경영학·경제학·통계학·회계학 관련 학과를 졸업한 후 은행, 신용평가사, 증권사, 캐피탈회사 등 금융기관에 입사하는 것이 일반적이다.[1] 입사 후 여신심사팀·신용리스크팀에 배치되어 기업 재무제표 분석, 신용등급 산정, 대출 심사 등의 업무를 수행하며 전문성을 쌓는다.[2] 공인재무분석사(CFA), 재무위험관리사(FRM) 등 전문 자격을 취득하면 경력 발전에 유리하다.[3] 경력 5년 이상이면 선임 애널리스트나 팀장급으로 승진할 수 있다.[4]","overviewSalary":{"sal":"신용분석가의 평균 연봉은 약 5,000만~8,000만 원 수준이다.[1] 은행권 정규직의 경우 복리후생이 우수하고, 신용평가회사(NICE, KIS) 전문 분석가는 경력에 따라 억대 연봉도 가능하다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"신용분석가의 수요는 향후 5~10년간 완만한 성장세가 예상된다.[1] 핀테크 기업의 등장과 AI 신용평가 시스템 도입으로 일부 단순 업무는 자동화되지만, 복잡한 기업 신용 분석과 리스크 관리 역량을 갖춘 고급 인력의 수요는 유지된다.[2]","source":"한국고용정보원, 금융감독원(2024)"},"trivia":"한국의 3대 신용평가사(NICE신용평가, 한국신용평가, 한국기업평가)는 수천 개 기업의 채권 신용등급을 관리하며, 이 등급 하나가 기업의 자금 조달 비용을 크게 좌우한다.[1] 개인신용평가 체계인 NICE 신용점수는 1,000점 만점이며, 점수 10점 차이로 대출 금리가 수십만 원 달라질 수 있다.[2] 미국 2008년 금융위기 당시 신용평가사들의 오류 평가가 위기를 심화시켜 신용분석가의 역할이 전 세계적으로 재조명되었다.[3]","detailWlb":{"wlb":"보통이하","social":"높음","wlbDetail":"결산 시즌이나 기업 심사 마감일에는 야근이 빈번하며, 정확성에 대한 압박이 높다. 오류 하나가 기업 신용등급과 수십억 원의 대출 조건에 영향을 미칠 수 있어 정신적 스트레스가 상당하다.","socialDetail":"금융업 내에서 전문 분석가로 인정받으며 사회적 지위가 높다. 기업 CFO·임원들과 직접 소통하는 경우가 많아 비즈니스 네트워크가 광범위하게 형성된다."},"detailReady":{"curriculum":["경영학·경제학·통계학·회계학 전공 이수","재무제표 분석 및 기업 가치평가 실습","금융기관 인턴십을 통한 여신심사 실무 경험","CFA Level 1 시험 준비"],"recruit":["은행·금융지주사 리스크관리팀 공채 응시","신용평가사(NICE, KIS, KR) 애널리스트 채용 응시","캐피탈·저축은행 여신심사팀 경력직 지원"],"training":["CFA(공인재무분석사) 자격 취득","FRM(재무위험관리사) 자격 취득","신용위험분석사(CCRA) 자격 취득","금융감독원 금융교육센터 신용분석 과정 수강"]},"sidebarJobs":["금융상품개발자","기업신용조사분석원","보험상품개발자","손해사정사","신용상담사","신용조사원","자산운용가","증권·외환딜러","투자분석가"],"sidebarMajors":["경영학과","경제학과","금융·보험학과","통계학과","세무·회계학과","경영정보학과"],"sidebarCerts":["CFA(공인재무분석사)","FRM(재무위험관리사)","신용위험분석사(CCRA)","공인회계사(CPA)","금융투자분석사"],"heroTags":["신용분석가","크레딧애널리스트","기업신용평가","금융분석","여신심사","신용평가"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":3,"text":"한국CFA협회","url":"https://www.cfakorea.or.kr/"},{"id":4,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":8,"text":"금융감독원","url":"https://www.fss.or.kr/"}],"trivia":[{"id":9,"text":"금융감독원 신용평가 보고서","url":"https://www.fss.or.kr/"},{"id":10,"text":"NICE평가정보","url":"https://www.niceinfo.co.kr/"},{"id":11,"text":"한국고용정보원 직업전망","url":"https://www.keis.or.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283427741398';

UPDATE jobs SET user_contributed_json = '{"way":"학습지·교육교구방문강사가 되려면 교육 관련 기업(웅진씽크빅, 대교, 구몬학습 등)의 방문교사 채용에 응시하거나, 프리랜서로 개인 과외를 병행하며 활동하는 것이 일반적이다.[1] 별도의 공식 자격 요건이 없는 경우도 많으나, 해당 교과 전문 지식과 아동·청소년과의 소통 능력이 필수적이다.[2] 교원자격증이나 사회복지사 자격이 있으면 취업에 유리하며,[3] 일정 경력 후에는 지역 총무나 관리자급으로 성장하기도 한다.[4]","overviewSalary":{"sal":"학습지·교육교구방문강사의 수입은 담당 학생 수와 수수료 구조에 따라 크게 달라진다.[1] 월 150만~250만 원 수준이 일반적이며, 담당 학생이 많을수록 수입이 높아진다. 경험 많은 방문강사는 월 300만 원 이상도 가능하다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"학습지 방문강사의 수요는 저출생 영향으로 전반적으로 감소 추세이다.[1] 다만 프리미엄 교육교구와 STEAM 교육 관련 방문학습 시장은 유지되고 있으며, 온라인 학습과 오프라인 방문을 결합한 하이브리드 방문교육 모델로 변화하는 중이다.[2]","source":"한국고용정보원, 교육부(2024)"},"trivia":"국내 방문학습 시장은 1970년대 구몬학습이 도입된 이후 급성장하여, 전성기에는 10만 명 이상의 방문교사가 활동한 것으로 추정된다.[1] 방문강사의 하루 평균 이동 거리는 30~50km에 달하며, 강사 한 명이 평균 15~25가정을 담당한다.[2] 최근 AI 학습 솔루션을 활용한 방문수업 형태로 진화하면서 기술 활용 능력이 방문강사의 새로운 역량으로 부상하고 있다.[3]","detailWlb":{"wlb":"보통이상","social":"보통","wlbDetail":"시간 관리를 스스로 할 수 있어 자유도가 높지만, 학생 수 확보를 위한 영업 부담이 있다. 이동 시간이 길고 날씨에 영향을 받으며, 수입이 고정되지 않아 불안정한 면이 있다.","socialDetail":"가정을 방문하여 아이들의 학습을 직접 돕는 역할로, 학부모들로부터 감사와 신뢰를 받는 경우가 많다. 지역 사회에서 친숙한 교육 조력자로 인식되기도 한다."},"detailReady":{"curriculum":["교육학·아동학 관련 전공 이수 또는 방문교사 양성 과정 수료","해당 교과(수학, 한글, 영어, 과학 등) 심화 학습","아동 발달 단계별 학습 지도법 습득","교육교구 활용 수업 시연 연습"],"recruit":["대형 교육기업(웅진씽크빅, 대교, 구몬학습, 빨간펜 등) 방문교사 채용 공고 응시","지역 교육 센터·공부방 강사 모집에 지원","개인 과외 병행 후 프리랜서로 전환"],"training":["교원자격증 취득(교대·사범대 또는 교육대학원 진학)","아동심리상담사·독서지도사 자격 취득","교육교구 전문가 과정 수료","방문교사 양성기관 단기 교육 수료"]},"sidebarJobs":["기술·기능계강사","문리학원강사","예능강사","외국어강사","인사·교육·훈련사무원","컴퓨터강사","학습지방문교사"],"sidebarMajors":["교육학과","교육공학과","아동·청소년복지학과","아동가족학과","경영학과","사회복지학과"],"sidebarCerts":["교원자격증","사회복지사","독서지도사","아동심리상담사","방문학습지도사"],"heroTags":["학습지강사","방문강사","교육교구","방문교사","홈러닝","유아학습지"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":3,"text":"Q-Net 교원자격정보","url":"https://www.q-net.or.kr/crf005.do?id=crf00505&gSite=Q&gId="},{"id":4,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":8,"text":"교육부 통계","url":"https://www.moe.go.kr/"}],"trivia":[{"id":9,"text":"한국학습지협회","url":"https://www.klea.or.kr/"},{"id":10,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":11,"text":"교육부 에듀테크 보고서","url":"https://www.moe.go.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283457922594';

UPDATE jobs SET user_contributed_json = '{"way":"산업전기공이 되려면 전기 관련 전문대학이나 직업훈련원을 졸업한 후 전기기능사 또는 전기산업기사 자격증을 취득하는 것이 기본 요건이다.[1] 자격 취득 후 공장, 발전소, 산업시설 등의 전기설비 시공·유지보수 업체에 취업한다.[2] 현장에서 3~5년 실무 경험을 쌓으면 전기기사 자격에 도전할 수 있으며, 이후 전기공사현장관리자나 전기공학기술자로 성장 가능하다.[3] 산업안전 관련 자격을 추가로 취득하면 안전관리자로도 활동할 수 있다.[4]","overviewSalary":{"sal":"산업전기공의 평균 연봉은 약 3,500만~5,000만 원 수준이다.[1] 경력과 보유 자격증에 따라 차이가 크며, 야간·교대 근무 수당과 위험 수당을 포함하면 실수령액이 더 높다. 숙련 전기기술자의 경우 연 6,000만 원 이상도 가능하다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"산업전기공의 수요는 향후 5~10년간 안정적으로 유지될 것으로 전망된다.[1] 제조업 자동화와 스마트팩토리 전환이 가속화되면서 고급 전기설비 기술자 수요는 오히려 증가하고 있으며, 신재생에너지 시설 확충으로 태양광·풍력 발전소 전기공 수요도 늘고 있다.[2]","source":"한국고용정보원, 전기공사협회(2024)"},"trivia":"산업전기공이 다루는 고압 전기 설비는 최대 수만 볼트(V)에 달하며, 안전 수칙 하나의 실수가 치명적 사고로 이어질 수 있어 숙련도와 집중력이 필수이다.[1] 스마트팩토리의 핵심은 전기·자동화 설비이며, 이를 설치·유지보수하는 산업전기공의 역할이 점점 더 중요해지고 있다.[2] 전기기사 자격은 국내 기술 자격 중 취업 활용도 상위 10위 안에 드는 인기 자격으로, 매년 수만 명이 응시한다.[3]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"생산 라인 정지를 최소화해야 하는 공장 특성상 야간·주말 긴급 출동이 빈번하다. 고소 작업, 고압 전기 취급 등 위험 환경에서 집중력을 유지해야 하므로 신체·정신적 피로가 크다.","socialDetail":"제조업 현장의 핵심 인력으로 설비 담당자와 현장 관리자로부터 신뢰를 받는다. 전기 자격증 소지자로서 전문 기술직에 대한 사회적 인정이 있으나, 현장 노동자로서 블루칼라 직종 이미지도 혼재한다."},"detailReady":{"curriculum":["전기공학과 또는 전기과 전문대학 이수","전기기능사 자격시험 준비(필기·실기)","산업용 전동기·제어반·배전판 실습 훈련","산업안전보건 기초 교육 이수"],"recruit":["산업단지 내 전기설비 시공업체 취업","발전소·제조공장 전기설비팀 채용 응시","전기공사 전문업체 인턴·보조기술원으로 입사 후 정규직 전환"],"training":["전기기능사 → 전기산업기사 → 전기기사 순차 취득","전기공사기사 자격 취득으로 시공 영역 확장","산업안전기사 취득으로 안전관리자 역할 겸직 가능","스마트팩토리 전기자동화 교육 수강"]},"sidebarJobs":["내선전기공","발전전기공무기술원","수도사업전기설비기술원","외선전기공","전기공사현장관리자","전기공학기술자"],"sidebarMajors":["전기공학과","전기전자공학과","전기과","전기제어공학과","전기전자과","전기자동화과"],"sidebarCerts":["전기기사","전기산업기사","전기공사기사","산업안전기사","전기기능사"],"heroTags":["산업전기공","전기기술자","공장전기","설비전기","전기배선","산업전기"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"Q-Net 전기기사 자격정보","url":"https://www.q-net.or.kr/crf005.do?id=crf00505&gSite=Q&gId="},{"id":2,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":3,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":4,"text":"한국전기공사협회","url":"https://www.keca.or.kr/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":8,"text":"한국전기공사협회","url":"https://www.keca.or.kr/"}],"trivia":[{"id":9,"text":"산업안전보건공단(KOSHA)","url":"https://www.kosha.or.kr/"},{"id":10,"text":"스마트제조혁신추진단","url":"https://www.smart-factory.kr/"},{"id":11,"text":"Q-Net 전기기사 통계","url":"https://www.q-net.or.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283511988597';

UPDATE jobs SET user_contributed_json = '{"way":"경비원이 되려면 만 18세 이상이면 누구나 지원 가능하며, 경비업법에 따라 일반경비원 신임교육(24시간)을 이수해야 한다.[1] 신임교육 수료 후 경비업체나 아파트·빌딩 관리업체에 취업한다. 특수경비원(공항·원자력시설 등)은 별도의 특수경비원 교육(88시간)을 추가로 이수해야 한다.[2] 경력을 쌓으면 경비반장·현장소장으로 승진할 수 있으며, 경비지도사 자격을 취득하면 경비원 교육·지도 업무를 담당할 수 있다.[3] 청원경찰에 지원하려면 별도의 채용 시험과 청원경찰 교육원 교육을 거쳐야 한다.[4]","overviewSalary":{"sal":"경비원의 평균 연봉은 약 2,400만~3,000만 원 수준으로, 최저임금 수준의 처우가 많다.[1] 아파트 경비원은 주·야간 교대근무 수당이 포함되며, 대형 건물·시설 경비원은 보안 책임 수준에 따라 처우가 다소 높다. 경비반장이나 현장소장급은 연 3,500만 원 이상도 가능하다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"경비원의 고용은 향후 5~10년간 감소세가 예상된다.[1] CCTV·AI 보안 시스템 등 무인 경비 기술의 발전으로 단순 순찰 인력 수요가 줄고 있다. 다만 대형 복합시설, 특수경비 구역 등 첨단 보안 장비와 인적 경비의 병행이 필요한 분야의 수요는 유지된다.[2]","source":"한국고용정보원, 경찰청(2024)"},"trivia":"한국의 민간경비 산업은 1970년대 초 시작되어 현재 약 20만 명 이상의 경비원이 종사하는 대규모 산업으로 성장했다.[1] 경비지도사 시험은 매년 수천 명이 응시하며, 합격률이 20~30% 수준의 비교적 어려운 자격시험이다.[2] 아파트 단지 1곳의 CCTV는 평균 100~200대에 달하며, 이를 모니터링하는 경비원의 역할이 최근 더욱 정교해지고 있다.[3]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"24시간 교대근무(주간·야간·비번 3교대)로 생활 리듬이 불규칙하다. 야간 근무 시 수면 부족과 피로 누적이 문제가 되며, 돌발 상황 발생 시 즉각 대응해야 하는 긴장감이 지속된다.","socialDetail":"사회 안전망을 지키는 역할이나 최저임금 수준의 처우로 인해 사회적 인식이 낮은 편이다. 주민·방문객 등 다양한 사람들과 접촉하며, 정중한 서비스 마인드와 갈등 관리 능력이 요구된다."},"detailReady":{"curriculum":["일반경비원 신임교육(24시간) 이수(경비협회 교육기관)","응급처치·심폐소생술(CPR) 교육 수강","보안시스템(CCTV·출입통제) 운용법 학습","소방안전관리 기초 교육 이수"],"recruit":["민간경비업체 일반경비원 채용 응시","아파트·건물 관리업체 경비 채용 공고 지원","공공기관(청원경찰) 채용 시험 응시"],"training":["경비지도사 자격증 취득(1·2종, 경찰청 시행)","소방안전관리자 자격 취득","기계경비산업기사 자격 취득","CCTV·보안시스템 운용 전문 교육 수강"]},"sidebarJobs":["경비반장","시설·특수경비원","무인경비시스템종사원","무인기계경비원","경찰관","경호원","청원경찰","교도관","소방관"],"sidebarMajors":["경찰행정학과","경호학과","경호스포츠과","사회복지학과","법학과","경찰행정과"],"sidebarCerts":["경비지도사","소방안전관리자","기계경비산업기사","응급처치사","소방시설관리사"],"heroTags":["경비원","보안요원","시설경비","경비직","보안관리","야간경비"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"경비업법(법제처)","url":"https://www.law.go.kr/"},{"id":2,"text":"경비협회 신임교육 안내","url":"https://www.ksa.or.kr/"},{"id":3,"text":"Q-Net 경비지도사","url":"https://www.q-net.or.kr/crf005.do?id=crf00505&gSite=Q&gId="},{"id":4,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":8,"text":"경찰청 민간경비 현황","url":"https://www.police.go.kr/"}],"trivia":[{"id":9,"text":"한국경비협회","url":"https://www.ksa.or.kr/"},{"id":10,"text":"Q-Net 경비지도사 시험 통계","url":"https://www.q-net.or.kr/"},{"id":11,"text":"국토교통부 공동주택관리 통계","url":"https://www.molit.go.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283283787881';

UPDATE jobs SET user_contributed_json = '{"way":"선박객실승무원이 되려면 항공서비스학과나 관광경영학과를 졸업하거나 해운회사·페리회사의 별도 채용 프로그램에 지원하는 것이 일반적이다.[1] 채용 후 STCW(선원 훈련·자격 및 당직 기준에 관한 국제협약) 기본 안전 교육을 이수해야 하며, 구명정 운용·화재 진압·응급처치 등의 실습을 거친다.[2] 외국어(영어, 일본어 등) 능력이 우수하면 국제 크루즈 선사 취업에 유리하며,[3] 경력을 쌓으면 선임승무원·선박사무장으로 승진할 수 있다.[4]","overviewSalary":{"sal":"선박객실승무원의 연봉은 승선하는 선박 규모와 운항 노선에 따라 크게 다르다.[1] 국내 여객선 승무원은 약 2,800만~3,500만 원, 대형 크루즈 선사의 경우 숙식 제공 및 팁 수입을 합산하면 연 4,000만~6,000만 원 이상을 기대할 수 있다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"선박객실승무원의 수요는 향후 5~10년간 완만한 성장세가 예상된다.[1] 크루즈 여행 시장의 글로벌 회복세와 제주·부산 항로 여객 수요 증가로 국내 여객선 서비스 인력 수요가 유지되며, 한국발 국제 크루즈 노선 확대로 취업 기회가 늘고 있다.[2]","source":"한국고용정보원, 해양수산부(2024)"},"trivia":"대형 크루즈 선박 한 척에는 최대 2,000~3,000명의 승객을 위해 약 1,000~1,500명의 승무원이 탑승한다.[1] STCW 협약은 전 세계 선원의 자격 기준을 통일하기 위해 1978년 제정되었으며, 현재 164개국이 가입하여 선박승무원 자격의 국제 기준이 되고 있다.[2] 크루즈 선사 승무원은 한 번의 계약 기간 동안 수십 개국의 항구를 방문하며, 다양한 문화를 직접 경험할 수 있는 직업이다.[3]","detailWlb":{"wlb":"보통이하","social":"보통이상","wlbDetail":"승선 중에는 육지와 격리되어 24시간 선내에서 생활하며, 장기 승선(4~8개월) 후 하선 휴가를 받는 패턴이 일반적이다. 가족·친구와 오랜 기간 떨어져야 하는 외로움이 크다.","socialDetail":"다국적 승객과 승무원을 만나며 글로벌 감각을 키울 수 있다. 항공 승무원보다 인지도가 낮지만, 선상에서 고객 서비스의 핵심을 담당하는 전문직으로 인식된다."},"detailReady":{"curriculum":["항공서비스학과·관광경영학과 전공 이수","STCW 기본 안전 교육 수료(구명정, 소화, 응급처치, 생존기술)","서비스 매너·선박 식음료 서비스 실습","영어·일본어 등 외국어 능력 강화"],"recruit":["국내 여객선·페리회사(팬스타, 씨스포빌 등) 채용 공고 응시","글로벌 크루즈 선사(Royal Caribbean, Carnival 등) 한국 대리점 통해 지원","해운회사 신입 공채 및 경력직 채용 응시"],"training":["STCW 기본 안전 과정 수료(해양수산부 인정 교육기관)","응급처치·해상 구조 전문 교육 이수","크루즈 서비스·식음료 관리 자격 취득","영어 면접 및 외국어 회화 집중 준비"]},"sidebarJobs":["고속열차팀장","선박사무장","여객선개찰원","여객전무","선박 및 열차객실승무원","열차승무원","전철차장","특급열차팀장","항공기객실승무원"],"sidebarMajors":["항공서비스과","항공서비스학과","관광경영학과","철도경영과","철도교통과","경영학과"],"sidebarCerts":["STCW기본안전교육수료증","구명정원자격","응급처치사","서비스경영사","식품위생관리사"],"heroTags":["선박승무원","크루즈승무원","해상서비스","여객선스탭","선박서비스","페리승무원"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"해양수산부 STCW 교육 안내","url":"https://www.mof.go.kr/"},{"id":3,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":4,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":8,"text":"해양수산부","url":"https://www.mof.go.kr/"}],"trivia":[{"id":9,"text":"한국크루즈산업협회","url":"https://www.cruisekorea.or.kr/"},{"id":10,"text":"IMO(국제해사기구) STCW","url":"https://www.imo.org/"},{"id":11,"text":"해양수산부 크루즈산업 보고서","url":"https://www.mof.go.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283478490375';

UPDATE jobs SET user_contributed_json = '{"way":"의학연구원이 되려면 의학·의생명과학·약학·생명공학 관련 학과를 졸업한 후 대학원에서 석사 또는 박사 학위를 취득하는 것이 일반적이다.[1] 학위 취득 후 대학병원 연구소, 국립보건연구원, 제약회사 연구개발팀, 의료기기 회사 등에 취업하여 기초 및 임상 연구를 수행한다.[2] 임상연구전문가(CCRP) 자격을 취득하면 임상시험 분야에서의 경력 개발에 유리하며,[3] 박사후연구원(포닥) 과정을 거쳐 독립 연구자나 PI(연구책임자)로 성장하는 경우도 많다.[4]","overviewSalary":{"sal":"의학연구원의 연봉은 소속 기관과 경력에 따라 크게 다르다.[1] 대학교수 겸직 연구자는 6,000만~1억 원, 제약사 연구원은 4,000만~7,000만 원, 국공립 연구소 연구원은 3,500만~6,000만 원 수준이다. 박사후연구원은 3,000만~4,500만 원 수준이다.[2]","source":"워크넷, 직업백과(2024)"},"overviewProspect":{"main":"의학연구원의 수요는 향후 10년간 성장세가 예상된다.[1] 바이오·헬스케어 산업의 급성장과 정부의 의생명과학 R&D 투자 확대, 고령화에 따른 신약·의료기술 개발 수요 증가로 고급 의학연구 인력에 대한 수요가 높아지고 있다.[2]","source":"한국고용정보원, 보건복지부(2024)"},"trivia":"한국의 신약 개발 성공률은 전 세계 평균과 비슷한 약 0.01%로, 1만 개의 후보 물질 중 최종 신약으로 출시되는 것은 단 1개 정도이다.[1] 국내 제약·바이오 기업의 R&D 투자 규모는 2023년 기준 약 4조 원을 넘어섰으며, 의학연구원 채용 수요도 꾸준히 증가하고 있다.[2] 노벨 생리의학상은 매년 기초의학 연구 성과에 수여되며, 2024년까지 한국인 수상자는 없지만 세계적 수준의 연구를 진행하는 한국 연구소가 늘고 있다.[3]","detailWlb":{"wlb":"보통이하","social":"높음","wlbDetail":"연구 마감이나 임상시험 진행 시기에는 주말도 반납하는 경우가 빈번하다. 실험 스케줄에 따라 심야 작업이 필요하기도 하며, 연구 결과에 대한 압박이 상당하다.","socialDetail":"의사·과학자로서 전문직 이미지로 사회적 존경을 받는다. 신약 개발이나 질병 치료법 발견 등 인류에 직접 기여하는 성취감이 높아 직업 만족도가 높은 편이다."},"detailReady":{"curriculum":["의학·의생명과학·약학·생명공학 학사 및 석·박사 과정 이수","실험 기법(PCR, 세포배양, 동물실험 등) 숙련","SCI 논문 작성 및 영어 학술 글쓰기 역량 배양","임상연구 윤리(IRB) 이해 및 GCP(의약품 임상시험 관리기준) 교육"],"recruit":["대학병원·의과대학 연구소 연구원 채용 응시","국립보건연구원·질병관리청 등 공공 연구기관 채용 공고 지원","제약사(한미약품, 셀트리온, 삼성바이오로직스 등) 연구개발팀 공채 응시"],"training":["임상연구전문가(CCRP) 자격 취득","실험동물기술원 자격 취득","의학통계 및 생물정보학 기초 역량 강화","SCI급 논문 게재를 통한 연구 경력 구축"]},"sidebarJobs":["농림어업시험원","농학연구원","독성시험연구원","생명과학시험원","수산학연구원","약학연구원","임학 및 산림학연구원","축산학 및 수의학연구원"],"sidebarMajors":["의학과","생명과학과","생명공학과","약학과","수의학과","심리학과"],"sidebarCerts":["의사면허","임상연구전문가(CCRP)","실험동물기술원","의학박사학위","생명정보학전문가"],"heroTags":["의학연구원","의과학자","의학연구","임상연구","기초의학","의생명연구"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":3,"text":"한국임상연구전문가협회","url":"https://www.kcra.kr/"},{"id":4,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewSalary.sal":[{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"},{"id":6,"text":"직업백과","url":"https://job.asamaru.net/"}],"overviewProspect.main":[{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":8,"text":"보건복지부 보건산업 통계","url":"https://www.mohw.go.kr/"}],"trivia":[{"id":9,"text":"한국제약바이오협회","url":"https://www.kpbma.or.kr/"},{"id":10,"text":"한국제약바이오협회 R&D 현황","url":"https://www.kpbma.or.kr/"},{"id":11,"text":"한국연구재단 노벨상 분석","url":"https://www.nrf.re.kr/"}],"detailWlb.wlbDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/seek/wantedInfo/jobIntro.do"}],"detailWlb.socialDetail":[{"id":13,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283433280884';
